// Find the jest-results artifact
const artifacts = $input.first().json.artifacts || [];
const jestArtifact = artifacts.find(a => a.name === 'jest-results');
const playwrightArtifact = artifacts.find(a => a.name === 'playwright-report');

if (!jestArtifact && !playwrightArtifact) {
  throw new Error('No test result artifacts found in this CI run');
}

return [{
  json: {
    ...($input.first().json),
    jest_artifact_id: jestArtifact?.id,
    jest_artifact_url: jestArtifact?.archive_download_url,
    playwright_artifact_id: playwrightArtifact?.id,
    playwright_artifact_url: playwrightArtifact?.archive_download_url,
    original_payload: $('GitHub CI Webhook').first().json.body,
  }
}];

// Merge all test result JSON files into one payload for Claude
const items = $input.all();
const results = [];

for (const item of items) {
  if (item.binary) {
    for (const [key, binaryData] of Object.entries(item.binary)) {
      try {
        const text = Buffer.from(binaryData.data, 'base64').toString('utf-8');
        const parsed = JSON.parse(text);
        // Determine source type from filename
        const source = key.includes('backend') ? 'jest-backend' :
                       key.includes('frontend') ? 'jest-frontend' :
                       key.includes('integration') ? 'jest-integration' : 'jest';

        // Flatten test results
        const tests = [];
        for (const suite of (parsed.testResults || [])) {
          const shortPath = suite.testFilePath
            .replace(/\\/g, '/')
            .split('/')
            .slice(-2)
            .join('/');
          for (const t of (suite.testResults || [])) {
            tests.push({
              name: t.fullName,
              suite: shortPath,
              status: t.status,
              duration_ms: t.duration || 0,
              failure_messages: (t.failureMessages || []).map(m => m.split('\n')[0].substring(0, 120))
            });
          }
        }

        results.push({
          source,
          run_summary: {
            total_tests: parsed.numTotalTests,
            passed: parsed.numPassedTests,
            failed: parsed.numFailedTests,
            skipped: parsed.numPendingTests,
          },
          tests
        });
      } catch(e) {
        console.log(`Skipping non-JSON file: ${key}`);
      }
    }
  }
}

const originalPayload = $('Find Artifact IDs').first().json.original_payload;

return [{
  json: {
    ...originalPayload,
    test_results: results,
    total_sources: results.length,
  }
}];

