// Extract and parse the Claude response
const claudeResponse = $input.first().json;
const rawText = claudeResponse.content[0].text.trim();
let analysis;
try {
  analysis = JSON.parse(rawText);
} catch(e) {
  throw new Error(`Claude returned invalid JSON: ${rawText.substring(0, 200)}`);
}

// Build markdown PR comment
const s = analysis.run_summary;
const healthEmoji = s.overall_health === 'healthy' ? '✅' : s.overall_health === 'degraded' ? '⚠️' : '🔴';
const originalPayload = $('Find Artifact IDs').first().json.original_payload;

let comment = `## ${healthEmoji} AI Test Analysis — ${s.overall_health.toUpperCase()}\n\n`;
comment += `> ${s.health_reason}\n\n`;
comment += `| Metric | Value |\n|--------|-------|\n`;
comment += `| Total Tests | ${s.total_tests} |\n`;
comment += `| ✅ Passed | ${s.passed} |\n`;
comment += `| ❌ Failed | ${s.failed} |\n`;
comment += `| ⏭ Skipped | ${s.skipped} |\n\n`;

if (analysis.failed_tests && analysis.failed_tests.length > 0) {
  comment += `### ❌ Failed Tests\n\n`;
  for (const t of analysis.failed_tests) {
    comment += `**${t.name}**\n`;
    comment += `- Suite: \`${t.suite}\`\n`;
    comment += `- Type: \`${t.failure_type}\`\n`;
    comment += `- Error: ${t.error_message}\n`;
    comment += `- 💡 Fix: ${t.fix_hint}\n\n`;
  }
}

if (analysis.brittle_tests && analysis.brittle_tests.length > 0) {
  comment += `### ⚠️ Brittle Tests\n\n`;
  for (const t of analysis.brittle_tests) {
    comment += `- **${t.name}** (\`${t.suite}\`) — ${t.reason}\n`;
  }
  comment += `\n`;
}

if (analysis.top_priority_fixes && analysis.top_priority_fixes.length > 0) {
  comment += `### 🎯 Top Priority Fixes\n\n`;
  analysis.top_priority_fixes.forEach((fix, i) => {
    comment += `${i + 1}. ${fix}\n`;
  });
  comment += `\n`;
}

if (analysis.suggested_new_test && analysis.suggested_new_test.test_name) {
  const sug = analysis.suggested_new_test;
  comment += `### 💡 Suggested New Test\n\n`;
  comment += `**${sug.test_name}**\n`;
  comment += `- File: \`${sug.target_suite}\`\n`;
  comment += `- What to assert: ${sug.what_to_assert}\n`;
  comment += `- Why: ${sug.rationale}\n\n`;
}

comment += `---\n*AI analysis powered by Claude. [View full results](https://github.com/${originalPayload.repo}/actions/runs/${originalPayload.run_id})*`;

return [{
  json: {
    ...originalPayload,
    analysis,
    pr_comment: comment,
    has_pr: !!(originalPayload.pr_number && originalPayload.pr_number !== ''),
  }
}];
